// Define a generic type guard function isOdd<T>(n: T): n is T & { odd: true }
function isOdd<T>(n: T): n is T & { odd: true } {
  return (n as any) % 2 !== 0;
}
// Solve the problem using the isOdd type guard function
var solve = function(n: number): boolean {
  // Use the isOdd type guard function to narrow the type of the input number
  if (isOdd(n)) {
    // If the number is odd, return true
    return true;
  } else {
    // If the number is not odd, return false
    return false;
  }
};

solutions.python:
class Solution:
  def is_odd(self, n):
    return (n % 2) != 0

  def solve(self, n):
    # Use the is_odd type guard function to narrow the type of the input number
    if self.is_odd(n):
      # If the number is odd, return True
      return True
    else:
      # If the number is not odd, return False
      return False
